'use client'

// src/progress.web.tsx
import * as Progress from "@radix-ui/react-progress";
import { Slot } from "@rn-primitives/slot";
import * as React from "react";
import { View } from "react-native";
var ProgressContext = React.createContext(null);
var Root2 = ({ asChild, value, max, getValueLabel, ref, ...props }) => {
  const Component = asChild ? Slot : View;
  return <ProgressContext.Provider value={{ value, max }}>
      <Progress.Root value={value} max={max} getValueLabel={getValueLabel} asChild>
        <Component ref={ref} {...props} />
      </Progress.Root>
    </ProgressContext.Provider>;
};
Root2.displayName = "RootProgress";
var Indicator2 = ({ asChild, ref, ...props }) => {
  const Component = asChild ? Slot : View;
  return <Progress.Indicator asChild>
      <Component ref={ref} {...props} />
    </Progress.Indicator>;
};
Indicator2.displayName = "IndicatorProgress";
export {
  Indicator2 as Indicator,
  Root2 as Root
};
